{
  "verses": [
    {
      "n": 16,
      "column": "left",
      "text": "Tà buhs winnam Salih- \ndsinachnu darriht pahr to fweh- \ntu Weetu Israëta Behrnu Ne- \nschkihstibas deht/un winnam Pahr- \nkahpschannu deht par wiffeem win- \nnu Grehkeem / un ta buhs win- \nnam tai Sa-eefchanas Telti dar- \nriht/ kas pee winneem paleek win- \nnu Neschkikhstibas deht."
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un ne weenam Zilwekam \nbuhs Sa-eefchanas Telti buht / \nkad wiꞥsch ee-ees Salihdsinafcha- \nnu darriht fivehta Weetâ / tee- \nkans wiꞥsch iseet/ ta buhs win- \nnam Salihdsinafchanu darriht \npreefsch few / un preefsch fawu \nNaminu/un preefsch wiffas Israë- \nta Draudses."
    },
    {
      "n": 18,
      "column": "left",
      "text": "Pehz to buhs winnam pee \nta Altara/ kas preefsch ta KUN- \nGA irr/iseet/ un preefsch winna \nSalihdsinafchanu darriht / tad \nbuhs winnam no ta Wehrfcha \nAffini / un no ta Auna Affini \nxeint/ un us ta Altara Raggeem \napfahrt lift."
    },
    {
      "n": 19,
      "column": "left",
      "text": "Un winnam buhs ar fawu \nPirfsiu no ta Affins feptinkahrt \nus to flaziht / un to schkihstiht/ \nun fwehtiht no Israëta Behrnu \nNeschkihstibahn."
    },
    {
      "n": 20,
      "column": "left",
      "text": "Kad nu wiꞥsch irr pabei- \ndsís falihdsinaht to fwehtu Wee- \ntu/ un to Sa-eefchanas Telti/un \nto Altari / tad buhs winnam to \ndsihwo Ahfi peewest."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Un Aaronam buhs fawas \nabbejas Rohkas us ta dsihwa Ah- \nscha Galwu likt / un us to wiffus \nIsraëta Behrnu Noseegumus /"
    },
    {
      "n": 16,
      "column": "right",
      "text": "un wiffas winnam Pahrfkahpscha- \nnas pehz wiffeem winnam Greh- \nkeem fuhdseht/ tad buhs winnam \ntohs us ta Ahfcha Galwu likt/u \nto zaur weena finnama Wihr- \nRohku Tuksnefi palaist."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Tà buhs tain Ahfcham u \nfew wiffus winnam Noseegumu- \nus tukschu Weetu nest / un tan \nWihram buhs to Ahfi Tuksne- \npalaist."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Pehz to buhs Aaronam \nSa-eefchanas Telti nahkt / u \ntahs linnu Drehbes iswilkt / k \nwiꞥsch uswilzis bij fivehta Weet \needams / un winnam buhs tah- \ntur nolift."
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un winnam buhs faw \nMeesu fivehta Weetâ ar Uhden \npehrt/ un fawas paschas Drehbe \napwilkt / tad buhs winnam ise \nun fataifiht fawu Dedsamu-U \npuri / un to Lauschu Dedsamu \nUppuri/un preefsch few un preefs- \nteem Laudim Salihdsinafchan \ndarriht."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un winnam buhs arri t \nGrehku Uppura Taufus us t \nAltari eededfinaht."
    },
    {
      "n": 26,
      "column": "right",
      "text": "Un kas to palaischain \nAhfi palaidis irr / tam buhs fa \nwaz Drehbes masgaht / un faw \nMeesu ar Uhdeni pehrt / un peh \nto laid tas Lehgerti nahk."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Bet ta Grehku-Uppu- \nWehrfi / un ta Grehku-Lippu- \nAhfi / ka Affins eenests irr pa \nSalihdsinafchanu fivehta Weetá \ntohs buhs winnam iswest ahr \npreefsch Lehgera/un ar Ugguni fa"
    }
  ],
  "confidence": "high",
  "notes": ""
}
